This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i64 @sext_multi_uses(i64 %a, i1 %b, i64 %x) {
  %c = sext i1 %b to i64
  %d = xor i64 %a, %c
  %e = sub i64 %d, %c
  %f = mul i64 %x, %c
  %r = add i64 %f, %e
  ret i64 %r
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i64 @sext_multi_uses(i64 %a, i1 %b, i64 %x) {
  %1 = add i64 %x, %a
  %2 = sub i64 0, %1
  %r = select i1 %b, i64 %2, i64 %a
  ret i64 %r
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp:InstCombinerImpl::visitMul to implement the missed optimization:
```cpp
      X->getType()->isIntOrIntVectorTy(1) && X->getType() == Y->getType() &&
      (Op0->hasOneUse() || Op1->hasOneUse())) {
    Value *And = Builder.CreateAnd(X, Y, "mulbool");
    return CastInst::Create(Instruction::SExt, And, Ty);
  }

  // (zext bool X) * Y --> X ? Y : 0
  // Y * (zext bool X) --> X ? Y : 0
  if (match(Op0, m_ZExt(m_Value(X))) && X->getType()->isIntOrIntVectorTy(1))
    return SelectInst::Create(X, Op1, ConstantInt::getNullValue(Ty));
  if (match(Op1, m_ZExt(m_Value(X))) && X->getType()->isIntOrIntVectorTy(1))
    return SelectInst::Create(X, Op0, ConstantInt::getNullValue(Ty));

  Constant *ImmC;
  if (match(Op1, m_ImmConstant(ImmC))) {
    // (sext bool X) * C --> X ? -C : 0
    if (match(Op0, m_SExt(m_Value(X))) && X->getType()->isIntOrIntVectorTy(1)) {
      Constant *NegC = ConstantExpr::getNeg(ImmC);
      return SelectInst::Create(X, NegC, ConstantInt::getNullValue(Ty));
    }

    // (ashr i32 X, 31) * C --> (X < 0) ? -C : 0
    const APInt *C;
    if (match(Op0, m_OneUse(m_AShr(m_Value(X), m_APInt(C)))) &&
        *C == C->getBitWidth() - 1) {
      Constant *NegC = ConstantExpr::getNeg(ImmC);
